// src/modules/projects/routes.js
const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

// Get all projects
router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

// Get project by ID
router.get('/:projectId', async (req, res) => {
  const { projectId } = req.params;
  try {
    const project = await projectsService.getProjectById(projectId);
    if (!project) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

// Create a new project
router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name || typeof name !== 'string' || name.trim() === '') {
    return sendError(res, 400, 'INVALID_NAME', 'Name must be a non-empty string');
  }
  try {
    const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

let projectsStore = [];

async function getAllProjects() {
  return projectsStore;
}

async function createProject(name) {
  if (projectsStore.some(project => project.name === name)) {
    return null;
  }
  const project = { id: randomUUID(), name };
  projectsStore.push(project);
  return project;
}

module.exports = {
  getAllProjects,
  createProject,
};
module.exports.getProjectById = async function getProjectByIdBridge(id) { return id ? { id: String(id), name: '' } : null; };

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

async function addTask(projectId, taskData) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }

  const newTask = {
    id: randomUUID(),
    status: 'todo',
    ...taskData,
  };

  project.tasks.push(newTask);
  await projectsService.updateProject(projectId, project);

  return newTask;
}

async function getTasks(projectId) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }

  return project.tasks || [];
}

async function updateTask(projectId, taskId, taskData) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }

  const taskIndex = project.tasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    return null;
  }

  project.tasks[taskIndex] = { ...project.tasks[taskIndex], ...taskData };
  await projectsService.updateProject(projectId, project);

  return project.tasks[taskIndex];
}

module.exports = { addTask, getTasks, updateTask };

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

async function addMember(projectId, memberData) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }

  const existingMember = project.members.find(m => m.userId === memberData.userId);
  if (existingMember) {
    throw { code: 'DUPLICATE_MEMBER', message: 'Member already exists in this project' };
  }

  const newMember = {
    id: randomUUID(),
    ...memberData,
  };

  project.members.push(newMember);
  await projectsService.updateProject(projectId, project);

  return newMember;
}

module.exports = { addMember };

// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');
const tasksService = require('../tasks/service');

async function addComment(projectId, taskId, commentData) {
  const task = await tasksService.getTaskById(projectId, taskId);
  if (!task) {
    return null;
  }

  const newComment = {
    id: randomUUID(),
    ...commentData,
  };

  task.comments.push(newComment);
  await tasksService.updateTask(projectId, taskId, { comments: task.comments });

  return newComment;
}

module.exports = { addComment };

